import React from 'react';

const Dashboard = ({ userRole }) => {
  const getWelcomeMessage = () => {
    switch (userRole) {
      case 'admin':
        return {
          title: 'Welcome, Administrator!',
          message: 'Manage your clinic operations efficiently with our comprehensive dashboard.',
          color: 'from-purple-500 to-pink-500'
        };
      case 'doctor':
        return {
          title: 'Welcome, Doctor!',
          message: 'Have a nice time and try to care your patients kindly!!!',
          color: 'from-blue-500 to-green-500'
        };
      case 'receptionist':
        return {
          title: 'Welcome, Receptionist!',
          message: 'Manage patient registrations and appointments seamlessly.',
          color: 'from-green-500 to-teal-500'
        };
      case 'nurse':
        return {
          title: 'Welcome, Nurse!',
          message: 'Provide excellent patient care through efficient triage and vital monitoring.',
          color: 'from-pink-500 to-rose-500'
        };
      case 'lab_technician':
        return {
          title: 'Welcome, Lab Technician!',
          message: 'Process lab tests efficiently and ensure accurate results.',
          color: 'from-indigo-500 to-purple-500'
        };
      case 'pharmacist':
        return {
          title: 'Welcome, Pharmacist!',
          message: 'Manage prescriptions and inventory to ensure patient safety.',
          color: 'from-yellow-500 to-orange-500'
        };
      default:
        return {
          title: 'Welcome!',
          message: 'Welcome to the Clinic Management System.',
          color: 'from-gray-500 to-gray-600'
        };
    }
  };

  const getStats = () => {
    switch (userRole) {
      case 'doctor':
        return [
          { label: 'Patients in Queue', value: '8', icon: '👥', color: 'bg-blue-500' },
          { label: 'Today\'s Appointments', value: '15', icon: '📅', color: 'bg-green-500' }
        ];
      case 'receptionist':
        return [
          { label: 'Total Patients', value: '1,234', icon: '👥', color: 'bg-purple-500' },
          { label: 'Today\'s Check-ins', value: '45', icon: '✅', color: 'bg-blue-500' },
          { label: 'Pending Payments', value: '12', icon: '💰', color: 'bg-yellow-500' }
        ];
      case 'admin':
        return [
          { label: 'Total Patients', value: '1,234', icon: '👥', color: 'bg-purple-500' },
          { label: 'Active Doctors', value: '8', icon: '👨‍⚕️', color: 'bg-blue-500' },
          { label: 'Today\'s Appointments', value: '45', icon: '📅', color: 'bg-green-500' },
          { label: 'Revenue Today', value: 'ETB 12,500', icon: '💰', color: 'bg-yellow-500' }
        ];
      default:
        return [
          { label: 'Total Patients', value: '1,234', icon: '👥', color: 'bg-purple-500' },
          { label: 'Active Doctors', value: '8', icon: '👨‍⚕️', color: 'bg-blue-500' }
        ];
    }
  };

  const welcome = getWelcomeMessage();
  const stats = getStats();

  return (
    <div className="p-6">
      {/* Welcome Banner */}
      <div className={`bg-gradient-to-r ${welcome.color} rounded-lg p-8 mb-8 text-white`}>
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold mb-2">{welcome.title}</h1>
            <p className="text-lg opacity-90">{welcome.message}</p>
          </div>
          <div className="w-20 h-20 bg-white bg-opacity-20 rounded-full flex items-center justify-center">
            <span className="text-4xl">🏥</span>
          </div>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        {stats.map((stat, index) => (
          <div key={index} className="bg-white rounded-lg shadow-md p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-sm text-gray-600 mb-1">{stat.label}</p>
                <p className="text-2xl font-bold text-gray-800">{stat.value}</p>
              </div>
              <div className={`w-12 h-12 ${stat.color} rounded-full flex items-center justify-center text-white text-xl`}>
                {stat.icon}
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Recent Activity */}
      <div className="bg-white rounded-lg shadow-md p-6">
        <h3 className="text-lg font-semibold text-gray-800 mb-4">Recent Activity</h3>
        <div className="space-y-4">
          <div className="flex items-center justify-between py-3 border-b border-gray-200">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-blue-100 rounded-full flex items-center justify-center">
                <span className="text-blue-600 text-sm">👤</span>
              </div>
              <div>
                <p className="text-sm font-medium text-gray-900">New patient registered</p>
                <p className="text-xs text-gray-500">P-2023-0425 - Abebe Kebede</p>
              </div>
            </div>
            <span className="text-xs text-gray-500">2 mins ago</span>
          </div>

          <div className="flex items-center justify-between py-3 border-b border-gray-200">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-green-100 rounded-full flex items-center justify-center">
                <span className="text-green-600 text-sm">✓</span>
              </div>
              <div>
                <p className="text-sm font-medium text-gray-900">Payment confirmed</p>
                <p className="text-xs text-gray-500">ETB 850 - Consultation</p>
              </div>
            </div>
            <span className="text-xs text-gray-500">5 mins ago</span>
          </div>

          <div className="flex items-center justify-between py-3">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 bg-purple-100 rounded-full flex items-center justify-center">
                <span className="text-purple-600 text-sm">🔬</span>
              </div>
              <div>
                <p className="text-sm font-medium text-gray-900">Lab test completed</p>
                <p className="text-xs text-gray-500">Complete Blood Count</p>
              </div>
            </div>
            <span className="text-xs text-gray-500">10 mins ago</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
